SELECT id, customer_id AS "customerId", cart_id AS "cartId",
       state_id AS "stateId", flow_id AS "flowId",
       total_amount AS "totalAmount", created_time AS "createdAt"
FROM checkout

  AND id = #{id}
  AND customer_id = #{customerId}
  AND state_id = #{stateId}

ORDER BY created_time DESC

SELECT COUNT(*) FROM checkout

  AND state_id = #{stateId}
  AND customer_id = #{customerId}
